import{_ as a,o as t,c as s,ao as i}from"./chunks/framework.DXHZ1Ygx.js";const k=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"VectorDataCubes.jl","text":"Spatial indexing for vector data cubes","tagline":"A DimensionalData / Rasters array whose Geometry dimension is backed by a spatial index — so cube[Geometry(Contains(point))] just works.","actions":[{"theme":"brand","text":"Get started","link":"/examples/01_intro_nc_sids"},{"theme":"alt","text":"API reference","link":"/api"},{"theme":"alt","text":"View on GitHub","link":"https://github.com/asinghvi17/VectorDataCubes.jl"}]},"features":[{"title":"Spatial selectors","details":"Index a cube by geometry — cube[Geometry(Contains(point))], or plain X(a..b), Y(c..d) on the same axis — narrowed by an STRtree and refined by exact GeometryOps predicates."},{"title":"Zonal statistics → cubes","details":"VectorDataCubes.zonal aggregates a raster over geometries into a (Ti, Geometry) cube you can keep slicing spatially."},{"title":"Tables ↔ cubes","details":"vectordatacube lifts a GeoJSON / Shapefile / DataFrame into a cube; vectordatacubetable flattens it back, with real geometries and the CRS preserved."}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),o={name:"index.md"};function n(r,e,l,h,c,d){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h2 id="What-is-a-vector-data-cube?" tabindex="-1">What is a vector data cube? <a class="header-anchor" href="#What-is-a-vector-data-cube?" aria-label="Permalink to &quot;What is a vector data cube? {#What-is-a-vector-data-cube?}&quot;">​</a></h2><p>A <strong>vector data cube</strong> is a <a href="https://github.com/rafaqz/DimensionalData.jl" target="_blank" rel="noreferrer">DimensionalData</a> / <a href="https://github.com/rafaqz/Rasters.jl" target="_blank" rel="noreferrer">Rasters</a> array or stack whose <code>Geometry</code> dimension is backed by a <a href="/VectorDataCubes.jl/previews/PR13/api#VectorDataCubes.GeometryLookup"><code>GeometryLookup</code></a> — a vector of geometries plus an STRtree spatial index. You get everything DimensionalData and Rasters already give you (named dimensions, selectors, broadcasting, table conversion), <strong>plus</strong> spatial indexing on the geometry axis:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cube[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Geometry</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Contains</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(point))]   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># the geometry that contains a point</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cube[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">X</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(a </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> b), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Y</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(c </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> d)]        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># the same axis, selected by bounding box</span></span></code></pre></div><p>The geometry lookup spans both the <code>Geometry</code> dimension <em>and</em> the <code>(X(), Y())</code> it wraps, which is why geometry selectors and <code>X</code>/<code>Y</code> selectors both resolve against the one axis.</p><h2 id="Installation" tabindex="-1">Installation <a class="header-anchor" href="#Installation" aria-label="Permalink to &quot;Installation {#Installation}&quot;">​</a></h2><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Pkg</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Pkg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(url </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://github.com/asinghvi17/VectorDataCubes.jl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="Where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#Where-to-go-next" aria-label="Permalink to &quot;Where to go next {#Where-to-go-next}&quot;">​</a></h2><ul><li><p>The <a href="./examples/01_intro_nc_sids">examples</a> walk through building cubes, spatial selectors, zonal statistics, point extraction, and cubes with two geometry axes — ported from the Python (<code>xvec</code>) and R (<code>stars</code>) tutorials.</p></li><li><p>The <a href="./api">API reference</a> documents the public surface: <a href="/VectorDataCubes.jl/previews/PR13/api#VectorDataCubes.GeometryLookup"><code>GeometryLookup</code></a>, <a href="/VectorDataCubes.jl/previews/PR13/api#VectorDataCubes.vectordatacube"><code>vectordatacube</code></a>, <a href="/VectorDataCubes.jl/previews/PR13/api#VectorDataCubes.vectordatacubetable"><code>vectordatacubetable</code></a>, and <a href="/VectorDataCubes.jl/previews/PR13/api#VectorDataCubes.zonal"><code>VectorDataCubes.zonal</code></a>.</p></li></ul>`,8)])])}const u=a(o,[["render",n]]);export{k as __pageData,u as default};
